{{#invoke:template wrapper|wrap|_template=cite web
| _exclude     = id,symbol,name,taxon
| _reuse       = title
| last1        = NRCS
| author-link1 = Natural Resources Conservation Service
| url          = https://plants.sc.egov.usda.gov{{if last display both|/plant-profile/|{{if empty|{{{id|}}}|{{{symbol|}}}}}}}
| title        = {{if empty|{{#if:{{{title|}}}|<i>{{{title}}}</i>}}
                    |{{#if:{{{name|}}}|<i>{{{name}}}</i>}}
                    |{{#if:{{{taxon|}}}|<i>{{{taxon}}}</i>}}
                    |Plants Database{{if last display both|&nbsp;|{{if empty|{{{id|}}}|{{{symbol|}}}}}}}}}
| website      = {{#if:{{{title|}}}{{{name|}}}{{{taxon|}}}|PLANTS Database}}
| publisher    = [[United States Department of Agriculture]] (USDA)
}}<noinclude>
{{Documentation}}
</noinclude>

